changeSet.sql:
CREATE TABLE IF NOT EXISTS city ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name VARCHAR(255) NOT NULL, name_alt VARCHAR(255), type VARCHAR(128), region_name VARCHAR(255), region_fullname VARCHAR(255), region_type_short VARCHAR(32), created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP, CONSTRAINT uk_city_name_region UNIQUE (name, region_fullname) );
CREATE INDEX IF NOT EXISTS idx_city_name_lower ON city (LOWER(name));
CREATE INDEX IF NOT EXISTS idx_city_region_name_lower ON city (LOWER(region_name));
